const content = $input.first().json.text;
const topicId = $('Build Prompt').first().json.topicId;

// Extract title from frontmatter
const titleMatch = content.match(/^title:\s*"(.+?)(?<!\\)"/m);
const title = titleMatch ? titleMatch[1] : 'untitled';

// Derive slug: lowercase, alphanumeric + hyphens only
const slug = title
  .toLowerCase()
  .replace(/[^a-z0-9\s]/g, '')
  .trim()
  .replace(/\s+/g, '-');

// Estimate reading time (200 words per minute)
const wordCount = content.split(/\s+/).length;
const minutes = Math.ceil(wordCount / 200);
const readingTime = `${minutes} min read`;

// Replace the CALCULATE_THIS placeholder in the frontmatter
const finalContent = content.replace('CALCULATE_THIS', readingTime);

return [{
  json: {
    content: finalContent,
    slug,
    title,
    topicId,
    readingTime
  }
}];
